#include <bits/stdc++.h>
using namespace std;
int n,m,k,sum[102][102];
string s[102];
int f(int x1,int y1,int x2,int y2){
    return sum[x2][y2]-sum[x1-1][y2]-sum[x2][y1-1]+sum[x1-1][y1-1];
}
int main(){
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=n;i++){
        cin>>s[i];
        s[i]=" "+s[i];
        for(int j=1;j<=m;j++){
            sum[i][j]=sum[i-1][j]+sum[i][j-1]+(s[i][j]=='#')-sum[i-1][j-1];
        	//printf("%d ",sum[i][j]);
		}
		//printf("\n");
    }
    int ans=0;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            if(j+k-1<=m && f(i,j,i,j+k-1)==0){
            	//printf("%d %d -\n",i,j);
                ans++;
            }
            if(i+k-1<=n && f(i,j,i+k-1,j)==0){
            	//printf("%d %d 1\n",i,j);
                ans++;
            }
        }
    if(k==1)
        ans/=2;
    printf("%d",ans);
    return 0;
}
